150	// ExecuteInDir runs a command in the specified directory and captures output.
151	// It monitors stderr in real time and cancels the subprocess immediately if
152	// a known auth/rate-limit error pattern is detected.
153	func (e *OSExecutor) ExecuteInDir(ctx context.Context, binary string, args []string, stdin, dir string) (*ExecResult, error) {
154		ctx, cancel := context.WithCancel(ctx)
155		defer cancel()
156	
157		cmd := exec.Command(binary, args...)
158		cmdSetProcessGroup(cmd)
159		if dir != "" {
160			cmd.Dir = dir
161		}
162		cmd.Env = envWithOverrides(internalgit.CleanEnv(), executionEnvFromContext(ctx))
163	
164		stdoutPipe, err := cmd.StdoutPipe()
165		if err != nil {
166			return nil, err
167		}
168		stderrPipe, err := cmd.StderrPipe()
169		if err != nil {
170			return nil, err
171		}
172	
173		if stdin != "" {
174			cmd.Stdin = strings.NewReader(stdin)
175		}
176	
177		// Lock the OS thread before Start to ensure Pdeathsig is properly
178		// associated with this thread. Pdeathsig is sent when the thread dies,
179		// not the process, so we must prevent Go runtime from migrating the
180		// goroutine to a different thread during the critical exec operation.
181		// We unlock immediately after Start succeeds, as the kernel has already
182		// bound the child to this thread's PID via Pdeathsig.
183		runtime.LockOSThread()
184		err = cmd.Start()
185		runtime.UnlockOSThread()
186		if err != nil {
187			return nil, err
188		}
189	
190		var (
191			stdoutBuf         bytes.Buffer
192			stderrBuf         bytes.Buffer
193			cancelReason      string
194			timedOut          atomic.Bool
195			wallClockTimedOut atomic.Bool
196			wallClockElapsed  atomic.Int64 // nanoseconds; convert via time.Duration on read
197			killOnce          sync.Once
198		)
199	
200		stopProcess := func() {
201			killOnce.Do(func() {
202				cmdKillProcessGroup(cmd)
203			})
204		}
205	
206		activity := make(chan struct{}, 1)
207		pulse := func() {
208			select {
209			case activity <- struct{}{}:
210			default:
211			}
212		}
213	
214		idleTimeout := executionTimeoutFromContext(ctx)
215		if idleTimeout > 0 {
216			go func() {
217				timer := time.NewTimer(idleTimeout)
218				defer timer.Stop()
219				for {
220					select {
221					case <-ctx.Done():
222						stopProcess()
223						return
224					case <-activity:
225						if !timer.Stop() {
226							select {
227							case <-timer.C:
228							default:
229							}
230						}
231						timer.Reset(idleTimeout)
232					case <-timer.C:
233						timedOut.Store(true)
234						stopProcess()
235						return
236					}
237				}
238			}()
239		} else {
240			go func() {
241				<-ctx.Done()
242				stopProcess()
243			}()
244		}
245	
246		// Wall-clock watchdog: fires at an absolute deadline regardless of
247		// stream activity. Runs alongside the idle watchdog so a provider that
248		// emits heartbeats cannot defeat the overall bound. See RC2 of
249		// ddx-0a651925 for the incident that motivated this timer.
250		wallClock := executionWallClockFromContext(ctx)
251		if wallClock > 0 {
252			wallClockStart := time.Now()
253			go func() {
254				timer := time.NewTimer(wallClock)
255				defer timer.Stop()
256				select {
257				case <-ctx.Done():
258					return
259				case <-timer.C:
260					wallClockTimedOut.Store(true)
261					wallClockElapsed.Store(int64(time.Since(wallClockStart)))
262					cancel()
263					stopProcess()
264				}
265			}()
266		}
267	
268		// Stream stdout to collect it and count any write as progress.
269		stdoutDone := make(chan struct{})
270		go func() {
271			defer close(stdoutDone)
272			_, _ = io.Copy(&activityWriter{Buffer: &stdoutBuf, OnWrite: pulse}, stdoutPipe)
273		}()
274	
275		// Stream stderr: collect it, count progress, and watch for cancel patterns.
276		stderrDone := make(chan struct{})
277		go func() {
278			defer close(stderrDone)
279			scanner := bufio.NewScanner(stderrPipe)
280			for scanner.Scan() {
281				line := scanner.Text()
282				stderrBuf.WriteString(line)
283				stderrBuf.WriteByte('\n')
284				pulse()
285				if cancelReason == "" {
286					if reason := matchesCancelPattern(line); reason != "" {
287						cancelReason = reason
288						cancel()
289						stopProcess()
290					}
291				}
292			}
293			// Drain any remaining bytes not caught by the scanner.
294			_, _ = io.Copy(&activityWriter{Buffer: &stderrBuf, OnWrite: pulse}, stderrPipe)
295		}()
296	
297		<-stdoutDone
298		<-stderrDone
299		runErr := cmd.Wait()
300	
301		result := &ExecResult{
302			Stdout:           stdoutBuf.String(),
303			Stderr:           stderrBuf.String(),
304			EarlyCancel:      cancelReason != "",
305			CancelReason:     cancelReason,
306			WallClockTimeout: wallClockTimedOut.Load(),
307			WallClockElapsed: time.Duration(wallClockElapsed.Load()),
308		}
309	
310		if runErr != nil {
311			if cancelReason != "" {
312				// We triggered the cancel; report as early-cancel rather than timeout.
313				result.ExitCode = -1
314				return result, nil
315			}
316			if wallClockTimedOut.Load() {
317				result.ExitCode = -1
318				return result, context.DeadlineExceeded
319			}
320			if timedOut.Load() {
321				result.ExitCode = -1
322				return result, context.DeadlineExceeded
323			}
324			if errors.Is(ctx.Err(), context.Canceled) || errors.Is(ctx.Err(), context.DeadlineExceeded) {
325				result.ExitCode = -1
326				return result, ctx.Err()
327			}
328			if exitErr, ok := runErr.(*exec.ExitError); ok {
329				result.ExitCode = exitErr.ExitCode()
330				return result, nil // non-zero exit is not an execution error
331			}
332			return result, runErr
333		}
334		return result, nil
335	}
