155	func looksLikeHarnessProcess(cmdline string) bool {
156		if strings.TrimSpace(cmdline) == "" {
157			return false
158		}
159		parts := strings.Fields(cmdline)
160		if len(parts) == 0 {
161			return false
162		}
163		switch filepath.Base(parts[0]) {
164		case "claude", "codex", "gemini", "opencode", "pi":
165			return true
166		default:
167			return false
168		}
169	}
