22	func (procOrphanHarnessScanner) Scan(ctx context.Context) ([]orphanHarnessProcess, error) {
23		entries, err := os.ReadDir("/proc")
24		if err != nil {
25			return nil, fmt.Errorf("read /proc: %w", err)
26		}
27		out := make([]orphanHarnessProcess, 0)
28		for _, entry := range entries {
29			if ctx != nil && ctx.Err() != nil {
30				return nil, ctx.Err()
31			}
32			if !entry.IsDir() {
33				continue
34			}
35			pid, err := strconv.Atoi(entry.Name())
36			if err != nil || pid <= 0 {
37				continue
38			}
39			proc, ok := inspectOrphanHarnessProcess(pid)
40			if !ok {
41				continue
42			}
43			out = append(out, proc)
44		}
45		return out, nil
