func TestWorkStartupReaper_KillsOrphanGrandchildProcessGroup(t *testing.T) {
	projectRoot := t.TempDir()
	tempRoot := filepath.Join(t.TempDir(), "exec-wt")
	require.NoError(t, os.MkdirAll(ddxroot.JoinProject(projectRoot), 0o755))
	t.Setenv(config.ExecutionWorktreeRootEnv, tempRoot)

	orphanBeadID := "ddx-deadbeef"
	orphanWorktree := filepath.Join(tempRoot, ExecuteBeadWtPrefix+orphanBeadID+"-20260527T090438-deadbeef")
	require.NoError(t, os.MkdirAll(orphanWorktree, 0o755))

	deadOwnerPID := deadPID(t)
	store := &fakeOrphanHarnessLeaseStore{
		leases: map[string]bead.ClaimLeaseRecord{
			orphanBeadID: {
				BeadID: orphanBeadID,
				PID:    deadOwnerPID,
			},
		},
	}
	var killed []int
	scanner := fakeOrphanHarnessScanner{
		processes: []orphanHarnessProcess{
			{
				PID:     7070,
				PPID:    1,
				Command: "claude --print -p --verbose --output-format stream-json " + filepath.Base(orphanWorktree),
				Cwd:     orphanWorktree,
			},
			{
				PID:     7071,
				PPID:    7070,
				Command: "/bin/sleep 3600",
				Cwd:     orphanWorktree,
			},
		},
	}

	reaped, err := reapOrphanedHarnessChildren(
		context.Background(),
		projectRoot,
		scanner,
		store,
		store,
		store,
		"worker-a",
		&bytes.Buffer{},
		nil,
		func(pid int) error {
			killed = append(killed, pid)
			return nil
		},
	)
	require.NoError(t, err)
	require.Equal(t, 1, reaped)
	// Only the orphaned harness PID should be passed to killGroup,
	// which kills the entire process group including grandchild processes.
	require.Equal(t, []int{7070}, killed)
	require.Equal(t, []string{orphanBeadID}, store.released)

	// Verify that events were recorded for the orphaned harness
	events := store.events[orphanBeadID]
	require.Len(t, events, 1)
	assert.Equal(t, "operator_attention", events[0].Kind)
	assert.Equal(t, "orphaned_harness_child", events[0].Summary)
}

func TestWorkStartupReaper_RecordsOperatorAttention(t *testing.T) {
	projectRoot := t.TempDir()
	tempRoot := filepath.Join(t.TempDir(), "exec-wt")
	require.NoError(t, os.MkdirAll(ddxroot.JoinProject(projectRoot), 0o755))
	t.Setenv(config.ExecutionWorktreeRootEnv, tempRoot)

	orphanBeadID := "ddx-deadbeef"
	orphanAttemptID := "20260527T090438-deadbeef"
	orphanWorktree := filepath.Join(tempRoot, ExecuteBeadWtPrefix+orphanBeadID+"-"+orphanAttemptID)
	require.NoError(t, os.MkdirAll(orphanWorktree, 0o755))

	deadOwnerPID := deadPID(t)
	store := &fakeOrphanHarnessLeaseStore{
		leases: map[string]bead.ClaimLeaseRecord{
			orphanBeadID: {
				BeadID: orphanBeadID,
				PID:    deadOwnerPID,
			},
		},
	}
	var emitted []map[string]any
	scanner := fakeOrphanHarnessScanner{
		processes: []orphanHarnessProcess{
			{
				PID:     8080,
				PPID:    1,
				Command: "codex exec --json -C " + filepath.Base(orphanWorktree),
				Cwd:     orphanWorktree,
			},
		},
	}

	reaped, err := reapOrphanedHarnessChildren(
		context.Background(),
		projectRoot,
		scanner,
		store,
		store,
		store,
		"worker-a",
		&bytes.Buffer{},
		func(event string, data map[string]any) {
			emitted = append(emitted, data)
		},
		func(pid int) error {
			return nil
		},
	)
	require.NoError(t, err)
	require.Equal(t, 1, reaped)

	// Verify operator_attention events were emitted
	require.Len(t, emitted, 1)
	eventData := emitted[0]
	assert.Equal(t, "orphaned_harness_child", eventData["reason"])
	assert.Equal(t, orphanBeadID, eventData["bead_id"])
	assert.Equal(t, float64(8080), eventData["process_pid"])
	assert.Equal(t, float64(1), eventData["process_parent_pid"])
	assert.Equal(t, float64(deadOwnerPID), eventData["claim_owner_pid"])
	assert.Equal(t, orphanWorktree, eventData["worktree"])
	assert.Equal(t, projectRoot, eventData["project_root"])

	// Verify diagnosis is present and meaningful
	diagnosis, ok := eventData["diagnosis"].(string)
	require.True(t, ok)
	assert.Contains(t, diagnosis, "orphaned harness child")
	assert.Contains(t, diagnosis, orphanWorktree)

	// Verify bead event has correct structure
	events := store.events[orphanBeadID]
	require.Len(t, events, 1)
	event := events[0]
	assert.Equal(t, "operator_attention", event.Kind)
	assert.Equal(t, "orphaned_harness_child", event.Summary)
	assert.Equal(t, "worker-a", event.Actor)
	assert.Equal(t, "ddx work", event.Source)
	assert.NotZero(t, event.CreatedAt)

	// Parse and verify event body contains expected fields
	var body map[string]any
	require.NoError(t, json.Unmarshal([]byte(event.Body), &body))
	assert.Equal(t, "orphaned_harness_child", body["reason"])
	assert.Equal(t, orphanBeadID, body["bead_id"])
	assert.Equal(t, float64(8080), body["process_pid"])
}

